function debounce(func, wait, options = {}) {
  let timeoutId = null
  let lastArgs = null
  let lastThis = null
  let result = null
  let lastCallTime = null
  let leading = options.leading ?? false
  let trailing = options.trailing ?? true
  let maxWait = options.maxWait
  let maxing = maxWait != null

  // 如果 leading 和 trailing 都没开，那这函数就没意义了
  if (!leading && !trailing) return () => null

  function invokeFunc(time) {
    const args = lastArgs
    const thisArg = lastThis
    lastArgs = lastThis = null
    lastCallTime = null
    result = func.apply(thisArg, args)
    return result
  }

  function leadingEdge(time) {
    // 触发 leading 边界
    lastCallTime = time
    timeoutId = setTimeout(timerExpired, wait)
    return leading ? invokeFunc(time) : result
  }

  function remainingWait(time) {
    const timeSinceLastCall = time - lastCallTime
    const timeWaiting = wait - timeSinceLastCall

    if (maxing) {
      const timeSinceMaxWait = time - lastCallTime
      const maxWaitRemaining = maxWait - timeSinceMaxWait
      return Math.min(timeWaiting, maxWaitRemaining)
    }

    return timeWaiting
  }

  function timerExpired() {
    const time = Date.now()
    if (trailing && lastArgs) {
      // 还有 pending 调用，触发 trailing
      const remain = remainingWait(time)
      if (remain <= 0) {
        trailingEdge(time)
      } else {
        // 还没到时间（被 maxWait 打断了），重新计时
        timeoutId = setTimeout(timerExpired, remain)
      }
    } else {
      timeoutId = null
      lastCallTime = null
    }
  }

  function trailingEdge(time) {
    timeoutId = null
    if (trailing && lastArgs) {
      return invokeFunc(time)
    }
    lastArgs = lastThis = null
    return result
  }

  function debounced(...args) {
    const time = Date.now()
    const isInvoking = shouldInvoke(time)

    lastArgs = args
    lastThis = this

    if (isInvoking) {
      if (timeoutId == null) {
        return leadingEdge(time)
      }

      if (maxing) {
        // 被 maxWait 强制触发
        timeoutId = clearTimeout(timeoutId)
        timeoutId = setTimeout(timerExpired, wait)
        return invokeFunc(time)
      }
    }

    if (timeoutId == null) {
      timeoutId = setTimeout(timerExpired, wait)
    }

    return result
  }

  function shouldInvoke(time) {
    const timeSinceLastCall = time - lastCallTime
    return lastCallTime == null || timeSinceLastCall >= wait || timeSinceLastCall < 0
  }

  debounced.cancel = function () {
    if (timeoutId != null) {
      clearTimeout(timeoutId)
    }
    timeoutId = null
    lastArgs = lastThis = null
    lastCallTime = null
  }

  debounced.flush = function () {
    if (timeoutId != null && lastArgs) {
      return trailingEdge(Date.now())
    }
    return result
  }

  return debounced
}
```

这个实现对标 Lodash 的 `_.debounce`，核心能力包括：

- **leading** — 是否在节流周期开头立即执行一次（默认 `false`）
- **trailing** — 是否在调用停止后延迟执行最后一次（默认 `true`）
- **maxWait** — 最长等待时间，保证函数至少每隔 maxWait 毫秒执行一次，防止被持续高频调用饿死
- **cancel()** 和 **flush()** — 取消和立即执行 pending 调用

简单用法：

```javascript
const onInput = debounce((e) => {
  console.log('搜索:', e.target.value)
}, 300)

input.addEventListener('input', onInput)
```

**直观理解**：debounce 就像一个电梯门——在 wait 时间内只要不断有人按开门（调用），门就一直不关；只有当最后一个人进来后过了 wait 毫秒没人再按，门才关上（执行回调）。`leading` 相当于第一个人刚进来时门立刻关上又打开，而 `maxWait` 是防止有人一直按着开门键让电梯永远关不上。

